targets.query:
from(bucket:"water")
  |> range(start:-24h)
  |> filter(fn:(r)=>r._field=="TDS" and r._measurement=="mqtt_consumer")
  |> map(fn:(r)=>({
      _time:r._time,
      CaMg: float(v:r._value)*0.5,
      Na: float(v:r._value)*0.2,
      Other: float(v:r._value)*0.3
  }))

join(
  tables: {
    t: from(bucket:"water") |> range(start:-24h) |> filter(fn:(r)=>r._field=="waterTemp"),
    h: from(bucket:"water") |> range(start:-24h) |> filter(fn:(r)=>r._field=="humidity")
  }, on:["_time"])
  |> map(fn:(r)=>({
      _time:r._time,
      _value: if r.waterTemp > 30.0 and r.humidity < 40.0 then 3.0
              else if r.waterTemp > 25.0 and r.humidity < 60.0 then 2.0
              else 1.0
  }))
  |> aggregateWindow(every:5m, fn:mean, createEmpty:false)
  |> yield(name:"evapRisk")
